const items = $input.all();
const result = {};

items.forEach((item, index) => {
  const fullName = item.json.fullName ?? '';
  const ccdPoint = item.json.ccdPoint;

  let ketQua;

  if (ccdPoint === null || ccdPoint === undefined || ccdPoint === '' || ccdPoint === 0) {
    ketQua = 'KHÔNG LÀM';
  } else if (ccdPoint >= 80) {
    ketQua = 'Đạt';
  } else if (ccdPoint >= 0 && ccdPoint < 80) {
    ketQua = 'Không Đạt';
  } else {
    ketQua = 'KHÔNG LÀM';
  }

  result[`item_${index}`] = `Tên: ${fullName} -- Điểm: ${ccdPoint ?? 'N/A'} -- Kết quả: ${ketQua}`;
});

return [
  {
    json: result
  }
];

const items = $input.all();
const result = {};

items.forEach((item, index) => {
  const fullName = item.json.fullName ?? '';
  const mrtPoint = item.json.mrtPoint;

  let ketQua;

  if (mrtPoint === null || mrtPoint === undefined || mrtPoint === '' || mrtPoint === 0) {
    ketQua = 'KHÔNG LÀM';
  } else if (mrtPoint >= 80) {
    ketQua = 'Đạt';
  } else if (mrtPoint >= 0 && mrtPoint < 80) {
    ketQua = 'Không Đạt';
  } else {
